export const colors = {
  primary: '#8b5cf6',
  secondary: '#ffb366',
  accent: '#ff8c42',
  background: '#1a1a1a',
  surface: 'rgba(26,26,26,0.85)',
  glass: 'rgba(26,26,26,0.92)',
  border: 'rgba(255,255,255,0.12)',
  text: '#EAEAEB',
  textMuted: 'rgba(255,255,255,0.7)',
  white: '#fff',
  black: '#000',
};

export const radii = {
  sm: '6px',
  md: '12px',
  lg: '20px',
  xl: '32px',
};

export const shadows = {
  modal: '0 20px 40px rgba(0,0,0,0.4), 0 8px 16px rgba(0,0,0,0.2)',
  glass: '0 8px 32px rgba(0,0,0,0.25), 0 2px 8px rgba(0,0,0,0.12)',
  button: '0 1px 4px rgba(0,0,0,0.04)',
};

export const font = {
  family: 'Inter, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif',
  size: '15px',
  weight: 500,
};
